option.value:
{% extends "base.html" %}

{% block title %}帖子列表{% endblock %}

{% block content %}
<style>
    .filter-row {
        grid-column: 1 / -1;
        display: flex;
        flex-wrap: wrap;
        align-items: center;
        gap: 8px;
    }
    .rent-tag {
        cursor: pointer;
        padding: 2px 8px;
    }
    .rent-tag.active {
        font-weight: bold;
        text-decoration: underline;
    }
    .rent-input {
        flex: 0 1 5em;
        min-width: 3em;
    }
</style>
<div class="card">
    <form id="filter-form" method="get" action="{{ url_for('posts.list_posts') }}" class="grid grid-2">
        <input type="hidden" id="hidden-min-rent" name="min_rent" value="{{ filters.min_rent }}">
        <input type="hidden" id="hidden-max-rent" name="max_rent" value="{{ filters.max_rent }}">
        <label>位置
            <select name="location">
                <option value="" {% if not filters.location %}selected{% endif %}>不限</option>
                <option value="港岛" {% if filters.location == '港岛' %}selected{% endif %}>港岛</option>
                <option value="九龙" {% if filters.location == '九龙' %}selected{% endif %}>九龙</option>
                <option value="新界" {% if filters.location == '新界' %}selected{% endif %}>新界</option>
                <option value="离岛" {% if filters.location == '离岛' %}selected{% endif %}>离岛</option>
            </select>
        </label>
        <label>附近学校
            <select name="nearby_school">
                <option value="" {% if not filters.nearby_school %}selected{% endif %}>不限</option>
                <option value="HKU" {% if filters.nearby_school == 'HKU' %}selected{% endif %}>香港大学</option>
                <option value="CUHK" {% if filters.nearby_school == 'CUHK' %}selected{% endif %}>香港中文大学</option>
                <option value="HKUST" {% if filters.nearby_school == 'HKUST' %}selected{% endif %}>香港科技大学</option>
                <option value="PolyU" {% if filters.nearby_school == 'PolyU' %}selected{% endif %}>香港理工大学</option>
                <option value="CityU" {% if filters.nearby_school == 'CityU' %}selected{% endif %}>香港城市大学</option>
                <option value="HKBU" {% if filters.nearby_school == 'HKBU' %}selected{% endif %}>香港浸会大学</option>
                <option value="LU" {% if filters.nearby_school == 'LU' %}selected{% endif %}>岭南大学</option>
                <option value="EdUHK" {% if filters.nearby_school == 'EdUHK' %}selected{% endif %}>香港教育大学</option>
            </select>
        </label>
        <div class="filter-row">
            <span>租金</span>
            <button type="button" class="rent-tag" data-min="" data-max="">不限</button>
            <button type="button" class="rent-tag" data-min="" data-max="3000">3000以下</button>
            <button type="button" class="rent-tag" data-min="3000" data-max="5000">3000-5000</button>
            <button type="button" class="rent-tag" data-min="5000" data-max="8000">5000-8000</button>
            <button type="button" class="rent-tag" data-min="8000" data-max="10000">8000-10000</button>
            <button type="button" class="rent-tag" data-min="10000" data-max="15000">10000-15000</button>
            <button type="button" class="rent-tag" data-min="15000" data-max="">15000以上</button>
            <input id="min-rent" class="rent-input" type="number" step="100" name="custom_min_rent" value="" placeholder="最低" aria-label="最低租金">
            <span>-</span>
            <input id="max-rent" class="rent-input" type="number" step="100" name="custom_max_rent" value="" placeholder="最高" aria-label="最高租金">
            <span>元</span>
        </div>
        <label>户型
            <input type="text" name="layout" value="{{ filters.layout }}" placeholder="例如：2室1厅">
        </label>
        <div style="align-self:end;">
            <button class="btn" type="submit">筛选</button>
            <a class="btn secondary inline" href="{{ url_for('posts.new_post') }}">发布新帖子</a>
        </div>
    </form>
</div>

<script>
    (function () {
        var form = document.getElementById("filter-form");
        var hiddenMinInput = document.getElementById("hidden-min-rent");
        var hiddenMaxInput = document.getElementById("hidden-max-rent");
        var minInput = document.getElementById("min-rent");
        var maxInput = document.getElementById("max-rent");
        var tags = document.querySelectorAll(".rent-tag");

        function setActive(target) {
            tags.forEach(function (tag) {
                tag.classList.remove("active");
            });
            if (target) {
                target.classList.add("active");
            }
        }

        tags.forEach(function (tag) {
            tag.addEventListener("click", function () {
                hiddenMinInput.value = tag.getAttribute("data-min") || "";
                hiddenMaxInput.value = tag.getAttribute("data-max") || "";
                minInput.value = "";
                maxInput.value = "";
                setActive(tag);
            });
        });

        function onCustomRentInput() {
            setActive(null);
            hiddenMinInput.value = "";
            hiddenMaxInput.value = "";
        }

        minInput.addEventListener("input", onCustomRentInput);
        maxInput.addEventListener("input", onCustomRentInput);

        form.addEventListener("submit", function () {
            if (minInput.value || maxInput.value) {
                hiddenMinInput.value = minInput.value;
                hiddenMaxInput.value = maxInput.value;
            }
        });

    })();
</script>

{% if posts %}
    <div class="grid grid-2">
        {% for item in posts %}
            <div class="card">
                <a href="{{ url_for('posts.post_detail', post_id=item.post.id) }}">
                    <img class="list-cover" src="{{ item.cover_url }}" alt="帖子封面">
                </a>
                <h3><a href="{{ url_for('posts.post_detail', post_id=item.post.id) }}">{{ item.post.title }}</a></h3>
                <p>租金：{{ item.post.rent }}</p>
                <p>位置：{{ item.post.location }}</p>
            </div>
        {% endfor %}
    </div>
{% else %}
    <div class="card">暂无帖子</div>
{% endif %}
{% endblock %}

{% extends "base.html" %}

{% block title %}帖子列表{% endblock %}

{% block content %}
<style>
    .filter-row {
        grid-column: 1 / -1;
        display: flex;
        flex-wrap: wrap;
