        <input type="hidden" id="hidden-max-rent" name="max_rent" value="{{ filters.max_rent }}">
        <label>位置
            <select name="location">
                <option value="" {% if not filters.location %}selected{% endif %}>不限</option>
                <option value="港岛" {% if filters.location == '港岛' %}selected{% endif %}>港岛</option>
                <option value="九龙" {% if filters.location == '九龙' %}selected{% endif %}>九龙</option>
                <option value="新界" {% if filters.location == '新界' %}selected{% endif %}>新界</option>
                <option value="离岛" {% if filters.location == '离岛' %}selected{% endif %}>离岛</option>
            </select>
        </label>
        <label>附近学校
            <select name="nearby_school">
                <option value="" {% if not filters.nearby_school %}selected{% endif %}>不限</option>
                <option value="HKU" {% if filters.nearby_school == 'HKU' %}selected{% endif %}>香港大学</option>
                <option value="CUHK" {% if filters.nearby_school == 'CUHK' %}selected{% endif %}>香港中文大学</option>
                <option value="HKUST" {% if filters.nearby_school == 'HKUST' %}selected{% endif %}>香港科技大学</option>
                <option value="PolyU" {% if filters.nearby_school == 'PolyU' %}selected{% endif %}>香港理工大学</option>
                <option value="CityU" {% if filters.nearby_school == 'CityU' %}selected{% endif %}>香港城市大学</option>
                <option value="HKBU" {% if filters.nearby_school == 'HKBU' %}selected{% endif %}>香港浸会大学</option>
                <option value="LU" {% if filters.nearby_school == 'LU' %}selected{% endif %}>岭南大学</option>
                <option value="EdUHK" {% if filters.nearby_school == 'EdUHK' %}selected{% endif %}>香港教育大学</option>
            </select>
        </label>
        <div class="filter-row">
            <span>租金</span>
            <button type="button" class="rent-tag {% if filters.min_rent == '' and filters.max_rent == '' %}active{% endif %}" data-min="" data-max="">不限</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '' and filters.max_rent == '3000' %}active{% endif %}" data-min="" data-max="3000">3000以下</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '3000' and filters.max_rent == '5000' %}active{% endif %}" data-min="3000" data-max="5000">3000-5000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '5000' and filters.max_rent == '8000' %}active{% endif %}" data-min="5000" data-max="8000">5000-8000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '8000' and filters.max_rent == '10000' %}active{% endif %}" data-min="8000" data-max="10000">8000-10000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '10000' and filters.max_rent == '15000' %}active{% endif %}" data-min="10000" data-max="15000">10000-15000</button>
            <button type="button" class="rent-tag {% if filters.min_rent == '15000' and filters.max_rent == '' %}active{% endif %}" data-min="15000" data-max="">15000以上</button>
            <input id="min-rent" class="rent-input" type="number" step="100" name="custom_min_rent" value="{% if filters.min_rent and (filters.min_rent, filters.max_rent) not in [('', ''), ('', '3000'), ('3000', '5000'), ('5000', '8000'), ('8000', '10000'), ('10000', '15000'), ('15000', '')] %}{{ filters.min_rent }}{% endif %}" placeholder="最低" aria-label="最低租金">
            <span>-</span>
            <input id="max-rent" class="rent-input" type="number" step="100" name="custom_max_rent" value="{% if filters.max_rent and (filters.min_rent, filters.max_rent) not in [('', ''), ('', '3000'), ('3000', '5000'), ('5000', '8000'), ('8000', '10000'), ('10000', '15000'), ('15000', '')] %}{{ filters.max_rent }}{% endif %}" placeholder="最高" aria-label="最高租金">
            <span>元</span>
        </div>
        <label>户型
            <select name="layout">
                <option value="" {% if not filters.layout %}selected{% endif %}>不限</option>
                <option value="开放式" {% if filters.layout == '开放式' %}selected{% endif %}>开放式 (Studio)</option>
                <option value="一房" {% if filters.layout == '一房' %}selected{% endif %}>一房</option>
                <option value="两房" {% if filters.layout == '两房' %}selected{% endif %}>两房</option>
                <option value="三房" {% if filters.layout == '三房' %}selected{% endif %}>三房</option>
                <option value="四房及以上" {% if filters.layout == '四房及以上' %}selected{% endif %}>四房及以上</option>
                <option value="其他" {% if filters.layout == '其他' %}selected{% endif %}>其他（劏房/套房等）</option>
            </select>
        </label>
        <div style="align-self:end;">
            <button class="btn" type="submit">筛选</button>
            <a class="btn secondary inline" href="{{ url_for('posts.new_post') }}">发布新帖子</a>
        </div>
    </form>
</div>

<script>
    (function () {
        var form = document.getElementById("filter-form");
        var hiddenMinInput = document.getElementById("hidden-min-rent");
        var hiddenMaxInput = document.getElementById("hidden-max-rent");
        var minInput = document.getElementById("min-rent");
        var maxInput = document.getElementById("max-rent");
        var tags = document.querySelectorAll(".rent-tag");

