                maxInput.value = "";
                setActive(tag);
            });
        });

        function onCustomRentInput() {
            setActive(null);
            hiddenMinInput.value = "";
            hiddenMaxInput.value = "";
        }

        minInput.addEventListener("input", onCustomRentInput);
        maxInput.addEventListener("input", onCustomRentInput);

        form.addEventListener("submit", function () {
            if (minInput.value || maxInput.value) {
                hiddenMinInput.value = minInput.value;
                hiddenMaxInput.value = maxInput.value;
            }
        });

    })();
</script>

